mapper.select:
SELECT c.id,
CASE c.type WHEN 'buy' THEN '采购单' WHEN 'bre' THEN '采购退货单' WHEN 'sell' THEN '销售单' WHEN 'sre' THEN '销售退货单' WHEN 'entry' THEN '其它入库单' WHEN 'extry' THEN '其它出库单' WHEN 'swap' THEN '调拨单' ELSE c.type END AS documentType,
-- 组织、往来单位 fr.name AS organization, COALESCE(sp.name, cu.name) AS partnerUnit,
-- 单据日期 / 编号（取对应 type 的抬头） DATE_FORMAT(COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time), '%Y-%m-%d') AS documentDate, COALESCE(buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number) AS documentNumber,
-- 费用类别 iet.name AS expenseType,
-- 结算状态与金额 CASE WHEN IFNULL(SUM(ci.money),0) = 0 THEN '未结算' WHEN IFNULL(SUM(ci.money),0) < c.money THEN '部分结算' ELSE '已结算' END AS settlementStatus,
c.money AS amount, IFNULL(SUM(ci.money),0) AS settledAmount, (c.money - IFNULL(SUM(ci.money),0)) AS unsettledAmount, IFNULL(SUM(ci.money),0) AS settlementAmount
FROM cost c LEFT JOIN iet ON iet.id = c.iet
/* 6 类上游抬头：用 c.class 关联 */ LEFT JOIN buy ON c.type='buy' AND buy.id = c.class LEFT JOIN bre ON c.type='bre' AND bre.id = c.class LEFT JOIN sell sel ON c.type='sell' AND sel.id = c.class LEFT JOIN sre ON c.type='sre' AND sre.id = c.class LEFT JOIN entry ent ON c.type='entry' AND ent.id = c.class LEFT JOIN extry ext ON c.type='extry' AND ext.id = c.class LEFT JOIN swap swp ON c.type='swap' AND swp.id = c.class
/* 组织、往来 */ LEFT JOIN frame fr ON fr.id = COALESCE(buy.frame, bre.frame, sel.frame, sre.frame, ent.frame, ext.frame, swp.frame) LEFT JOIN supplier sp ON sp.id = COALESCE(buy.supplier, bre.supplier, ent.supplier) LEFT JOIN customer cu ON cu.id = COALESCE(sel.customer, sre.customer, ext.customer)
/* 费用结算明细 */ LEFT JOIN cost_info ci ON ci.pid = c.id
AND c.type IN
#{dt}
AND c.iet IN
#{et}
AND ( (c.type='buy' AND buy.supplier = #{query.supplierId}) OR (c.type='bre' AND bre.supplier = #{query.supplierId}) OR (c.type='entry' AND ent.supplier = #{query.supplierId}) )
AND ( (c.type='sell' AND sel.customer = #{query.customerId}) OR (c.type='sre' AND sre.customer = #{query.customerId}) OR (c.type='extry' AND ext.customer = #{query.customerId}) )
AND ( buy.number LIKE CONCAT('%', #{query.orderNumber}, '%') OR bre.number LIKE CONCAT('%', #{query.orderNumber}, '%') OR sel.number LIKE CONCAT('%', #{query.orderNumber}, '%') OR sre.number LIKE CONCAT('%', #{query.orderNumber}, '%') OR ent.number LIKE CONCAT('%', #{query.orderNumber}, '%') OR ext.number LIKE CONCAT('%', #{query.orderNumber}, '%') )
AND DATE(COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time)) >= #{query.startDate}
AND DATE(COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time)) <= #{query.endDate}
AND (
( (#{ss} = 0 AND IFNULL((SELECT SUM(x.money) FROM cost_info x WHERE x.pid=c.id),0) = 0) OR (#{ss} = 1 AND IFNULL((SELECT SUM(x.money) FROM cost_info x WHERE x.pid=c.id),0) BETWEEN 0.0000001 AND c.money-0.0000001) OR (#{ss} = 2 AND IFNULL((SELECT SUM(x.money) FROM cost_info x WHERE x.pid=c.id),0) >= c.money) )
)
GROUP BY c.id, c.money, fr.name, sp.name, cu.name, iet.name, buy.id, bre.id, sel.id, sre.id, ent.id, ext.id, swp.id, buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number
ORDER BY COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time) DESC, c.id DESC

SELECT /* 主键 */ c.id,
CASE c.type WHEN 'buy' THEN '采购单' WHEN 'bre' THEN '采购退货单' WHEN 'sell' THEN '销售单' WHEN 'sre' THEN '销售退货单' WHEN 'entry' THEN '其它入库单' WHEN 'extry' THEN '其它出库单' WHEN 'swap' THEN '调拨单' ELSE c.type END AS documentType,
/* 组织 , 往来 */ fr.name AS organization, IF(c.type = 'swap', '-', COALESCE(sp.name, cu.name)) AS partnerUnit,
/* 单据日期 , 编号：优先上游抬头，其次 cost 自身兜底 */ DATE_FORMAT( COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time), '%Y-%m-%d' ) AS documentDate, COALESCE(buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number, c.class) AS documentNumber,
/* 费用类别 */ iet.name AS expenseType,
/* 结算状态（由明细求和得出） */ CASE WHEN IFNULL(SUM(ci.money), 0) = 0 THEN '未结算' WHEN IFNULL(SUM(ci.money), 0) < c.money THEN '部分结算' ELSE '已结算' END AS settlementStatus,
/* 金额 = cost.money */ c.money AS amount FROM cost c LEFT JOIN iet ON iet.id = c.iet
/* 七类上游抬头（兼容 class 存 id 或 number） */ LEFT JOIN buy ON c.type = 'buy' AND (buy.id = c.class OR buy.number = c.class) LEFT JOIN bre ON c.type = 'bre' AND (bre.id = c.class OR bre.number = c.class) LEFT JOIN sell sel ON c.type = 'sell' AND (sel.id = c.class OR sel.number = c.class) LEFT JOIN sre ON c.type = 'sre' AND (sre.id = c.class OR sre.number = c.class) LEFT JOIN entry ent ON c.type = 'entry' AND (ent.id = c.class OR ent.number = c.class) LEFT JOIN extry ext ON c.type = 'extry' AND (ext.id = c.class OR ext.number = c.class) LEFT JOIN swap swp ON c.type = 'swap' AND (swp.id = c.class OR swp.number = c.class)
/* 组织、往来 */ LEFT JOIN frame fr ON fr.id = COALESCE(buy.frame, bre.frame, sel.frame, sre.frame, ent.frame, ext.frame, swp.frame) LEFT JOIN supplier sp ON sp.id = COALESCE(buy.supplier, bre.supplier, ent.supplier) LEFT JOIN customer cu ON cu.id = COALESCE(sel.customer, sre.customer, ext.customer)
/* 费用结算明细（用于求已结算金额） */ LEFT JOIN cost_info ci ON ci.pid = c.id
AND ( (c.type = 'buy' AND buy.supplier = #{query.supplierId}) OR (c.type = 'bre' AND bre.supplier = #{query.supplierId}) OR (c.type = 'entry' AND ent.supplier = #{query.supplierId}) )
AND ( (c.type = 'sell' AND sel.customer = #{query.customerId}) OR (c.type = 'sre' AND sre.customer = #{query.customerId}) OR (c.type = 'extry' AND ext.customer = #{query.customerId}) )
AND ( buy.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR bre.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR sel.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR sre.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR ent.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR ext.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR swp.number LIKE CONCAT('%', #{query.documentNumber}, '%') OR c.class LIKE CONCAT('%', #{query.documentNumber}, '%') )
AND c.iet IN
#{eid}
AND DATE(COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time)) >= #{query.startDate}
AND DATE(COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time)) <= #{query.endDate}
AND c.state IN
#{ss}
AND c.type IN
#{dt}
/* 为了 PageHelper 的 count(*) 包裹子查询，需稳定的 GROUP BY */ GROUP BY c.id, c.money, fr.name, sp.name, cu.name, iet.name, buy.id, bre.id, sel.id, sre.id, ent.id, ext.id, swp.id, buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time, buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number, c.class
ORDER BY COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time) DESC, c.id DESC

SELECT c.id, c.data, i.name AS type, c.money FROM cost c LEFT JOIN iet i ON c.iet = i.id WHERE c.id IN
#{id}
/* 只返回未结算完的单据 */ AND c.state < 2

SELECT /* 主键 */ c.id,
CASE c.type WHEN 'buy' THEN '采购单' WHEN 'bre' THEN '采购退货单' WHEN 'sell' THEN '销售单' WHEN 'sre' THEN '销售退货单' WHEN 'entry' THEN '其它入库单' WHEN 'extry' THEN '其它出库单' WHEN 'swap' THEN '调拨单' ELSE c.type END AS documentType,
/* 组织、往来 */ fr.name AS organization, IF(c.type = 'swap', '-', COALESCE(sp.name, cu.name)) AS partnerUnit,
/* 单据日期、编号：优先上游抬头，其次用 cost 自身兜底 */ DATE_FORMAT( COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time), '%Y-%m-%d' ) AS documentDate, COALESCE(buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number, c.class) AS documentNumber,
/* 费用类别 */ iet.name AS expenseType,
/* 结算状态（由明细求和得出） */ CASE WHEN IFNULL(SUM(ci.money), 0) = 0 THEN '未结算' WHEN IFNULL(SUM(ci.money), 0) < c.money THEN '部分结算' ELSE '已结算' END AS settlementStatus,
/* 金额 */ c.money AS amount, IFNULL(SUM(ci.money), 0) AS settledAmount, (c.money - IFNULL(SUM(ci.money), 0)) AS unsettledAmount, IFNULL(SUM(ci.money), 0) AS settlementAmount
FROM cost c LEFT JOIN iet ON iet.id = c.iet
/* 7 类上游抬头（兼容 class 存 id 或 number） */ LEFT JOIN buy ON c.type = 'buy' AND (buy.id = c.class OR buy.number = c.class) LEFT JOIN bre ON c.type = 'bre' AND (bre.id = c.class OR bre.number = c.class) LEFT JOIN sell sel ON c.type = 'sell' AND (sel.id = c.class OR sel.number = c.class) LEFT JOIN sre ON c.type = 'sre' AND (sre.id = c.class OR sre.number = c.class) LEFT JOIN entry ent ON c.type = 'entry' AND (ent.id = c.class OR ent.number = c.class) LEFT JOIN extry ext ON c.type = 'extry' AND (ext.id = c.class OR ext.number = c.class) LEFT JOIN swap swp ON c.type = 'swap' AND (swp.id = c.class OR swp.number = c.class)
/* 组织、往来 */ LEFT JOIN frame fr ON fr.id = COALESCE(buy.frame, bre.frame, sel.frame, sre.frame, ent.frame, ext.frame, swp.frame) LEFT JOIN supplier sp ON sp.id = COALESCE(buy.supplier, bre.supplier, ent.supplier) LEFT JOIN customer cu ON cu.id = COALESCE(sel.customer, sre.customer, ext.customer)
/* 费用结算明细（用于求已结算金额） */ LEFT JOIN cost_info ci ON ci.pid = c.id
WHERE c.id IN
#{id}
/* 为了避免因明细多行导致重复，做稳定分组 */ GROUP BY c.id, c.money, fr.name, sp.name, cu.name, iet.name, buy.id, bre.id, sel.id, sre.id, ent.id, ext.id, swp.id, buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time, buy.number, bre.number, sel.number, sre.number, ent.number, ext.number, swp.number, c.class
ORDER BY COALESCE(buy.time, bre.time, sel.time, sre.time, ent.time, ext.time, swp.time, c.time) DESC, c.id DESC
